class CosmosQuery
{
    // EF 9 breaking change #3: Sync I/O now throws by default.
    // Use async APIs (ToListAsync) instead of ToList().
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator which works
        // because we preserved the old property name in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Converted from sync to async (EF Core 9 blocks sync by default).
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

